describe('getRemainingTTL', () => {
  let dateNowSpy: ReturnType<typeof vi.spyOn>;

  beforeEach(() => {
    dateNowSpy = vi.spyOn(Date, 'now').mockReturnValue(FIXED_NOW);
  });

  afterEach(() => {
    dateNowSpy.mockRestore();
  });

  it('returns full TTL for freshly created message', () => {
    const message = { timestamp: FIXED_NOW, ttl: 300 };
    expect(getRemainingTTL(message)).toBe(300);
  });

  it('returns half TTL when half the time has passed', () => {
    // age = 150s => remaining = 300 - 150 = 150
    const message = { timestamp: FIXED_NOW - 150000, ttl: 300 };
    expect(getRemainingTTL(message)).toBeCloseTo(150, 1);
  });

  it('returns 0 for fully expired message', () => {
    // age = 1000s > 300s ttl
    const message = { timestamp: FIXED_NOW - 1000000, ttl: 300 };
    expect(getRemainingTTL(message)).toBe(0);
  });

  it('returns full TTL for future timestamps (clamped age=0)', () => {
    const message = { timestamp: FIXED_NOW + 1000000, ttl: 300 };
    expect(getRemainingTTL(message)).toBe(300);
  });

  it('never returns negative value (clamped to 0)', () => {
    // age = 10000s >> 300s ttl
    const message = { timestamp: FIXED_NOW - 10000000, ttl: 300 };
    const result = getRemainingTTL(message);
    expect(result).toBe(0);
    expect(result).toBeGreaterThanOrEqual(0);
  });

  it('returns 0 when age exactly equals TTL', () => {
    const message = { timestamp: FIXED_NOW - 300000, ttl: 300 };
    expect(getRemainingTTL(message)).toBe(0);
  });

  it('return value is always between 0 and message.ttl', () => {
    const testCases = [
      { timestamp: FIXED_NOW, ttl: 300 },
      { timestamp: FIXED_NOW - 150000, ttl: 300 },
      { timestamp: FIXED_NOW - 300000, ttl: 300 },
      { timestamp: FIXED_NOW + 1000000, ttl: 300 },
      { timestamp: FIXED_NOW - 10000000, ttl: 300 },
      { timestamp: FIXED_NOW, ttl: 86400 },
    ];
    for (const msg of testCases) {
      const result = getRemainingTTL(msg);
      expect(result).toBeGreaterThanOrEqual(0);
      expect(result).toBeLessThanOrEqual(msg.ttl);
    }
  });

  it('throws on invalid timestamp', () => {
    const message = { timestamp: 'not-a-date', ttl: 300 } as any;
    expect(() => getRemainingTTL(message)).toThrow();
  });

  it('throws when ttl is missing', () => {
    const message = { timestamp: FIXED_NOW } as any;
    expect(() => getRemainingTTL(message)).toThrow();
  });

  it('throws when ttl is null', () => {
    const message = { timestamp: FIXED_NOW, ttl: null } as any;
    expect(() => getRemainingTTL(message)).toThrow();
  });

  it('works with ISO string timestamp', () => {
    const isoString = new Date(FIXED_NOW).toISOString();
    const message = { timestamp: isoString, ttl: 300 };
    expect(getRemainingTTL(message)).toBeCloseTo(300, 0);
  });
});

