describe('stampTTL', () => {
  it('sets ttl=300 for direct message type', () => {
    const pkg = { timestamp: FIXED_NOW } as any;
    const result = stampTTL(pkg, 'direct');
    expect(result.ttl).toBe(300);
  });

  it('sets ttl=3600 for private message type', () => {
    const pkg = { timestamp: FIXED_NOW } as any;
    const result = stampTTL(pkg, 'private');
    expect(result.ttl).toBe(3600);
  });

  it('sets ttl=86400 for public message type', () => {
    const pkg = { timestamp: FIXED_NOW } as any;
    const result = stampTTL(pkg, 'public');
    expect(result.ttl).toBe(86400);
  });

  it('returns the same object reference (mutation in place)', () => {
    const pkg = { timestamp: FIXED_NOW } as any;
    const result = stampTTL(pkg, 'direct');
    expect(result).toBe(pkg);
  });

  it('preserves all existing fields on the package', () => {
    const pkg = { timestamp: FIXED_NOW, foo: 'bar', baz: 42 } as any;
    const result = stampTTL(pkg, 'direct');
    expect(result.foo).toBe('bar');
    expect(result.baz).toBe(42);
    expect(result.timestamp).toBe(FIXED_NOW);
    expect(result.ttl).toBe(300);
  });

  it('overwrites an existing ttl field', () => {
    const pkg = { timestamp: FIXED_NOW, ttl: 9999 } as any;
    const result = stampTTL(pkg, 'direct');
    expect(result.ttl).toBe(300);
  });

  it('throws for unknown message type', () => {
    const pkg = { timestamp: FIXED_NOW } as any;
    expect(() => stampTTL(pkg, 'unknown' as any)).toThrow();
  });

  it('throws when messagePackage is null', () => {
    expect(() => stampTTL(null as any, 'direct')).toThrow();
  });

  it('throws when messagePackage is undefined', () => {
    expect(() => stampTTL(undefined as any, 'direct')).toThrow();
  });
});

describe('cross-function invariants', () => {
  let dateNowSpy: ReturnType<typeof vi.spyOn>;

  beforeEach(() => {
    dateNowSpy = vi.spyOn(Date, 'now').mockReturnValue(FIXED_NOW);
  });

  afterEach(() => {
    dateNowSpy.mockRestore();
  });

  it('isExpired agrees with getRemainingTTL: expired iff remaining <= 0', () => {
    const testMessages = [
      { timestamp: FIXED_NOW, ttl: 300 },
      { timestamp: FIXED_NOW - 150000, ttl: 300 },
      { timestamp: FIXED_NOW - 300000, ttl: 300 },
      { timestamp: FIXED_NOW - 500000, ttl: 300 },
      { timestamp: FIXED_NOW + 100000, ttl: 300 },
      { timestamp: FIXED_NOW, ttl: 86400 },
      { timestamp: FIXED_NOW - 86400000, ttl: 86400 },
      { timestamp: FIXED_NOW, ttl: 1 },
      { timestamp: FIXED_NOW - 1000, ttl: 1 },
    ];

    for (const msg of testMessages) {
      const expired = isExpired(msg);
      const remaining = getRemainingTTL(msg);

      if (expired) {
        expect(remaining).toBe(0);
      } else {
        expect(remaining).toBeGreaterThan(0);
      }
    }
  });

  it('getRebroadcastProbability returns 0.0 whenever isExpired returns true', () => {
    const expiredMessages = [
      { timestamp: FIXED_NOW - 500000, ttl: 300 },
      { timestamp: FIXED_NOW - 300000, ttl: 300 },
      { timestamp: FIXED_NOW - 86400000, ttl: 86400 },
      { timestamp: FIXED_NOW, ttl: 0 },
    ];

    for (const msg of expiredMessages) {
      expect(isExpired(msg)).toBe(true);
      expect(getRebroadcastProbability(msg)).toBe(0.0);
    }
  });

  it('stampTTL produces valid messages that are not expired when freshly stamped', () => {
    const types = ['direct', 'private', 'public'] as const;
    for (const type of types) {
      const pkg = { timestamp: FIXED_NOW } as any;
      stampTTL(pkg, type);
      expect(isExpired(pkg)).toBe(false);
      expect(getRemainingTTL(pkg)).toBe(getDefaultTTL(type));
      expect(getRebroadcastProbability(pkg)).toBeCloseTo(0.6, 5);
    }
  });

  it('age clamping: future timestamps always result in non-expired, full TTL, max probability', () => {
    const futureMsg = { timestamp: FIXED_NOW + 999999999, ttl: 300 };
    expect(isExpired(futureMsg)).toBe(false);
    expect(getRemainingTTL(futureMsg)).toBe(300);
    expect(getRebroadcastProbability(futureMsg)).toBeCloseTo(0.6, 5);
  });
});
